#include <stdio.h>
#include <fcntl.h>
#include <unistd.h>
#include <errno.h>
#include <string.h>

int main() {
 int fd;
 char buffer[100];

 // Open file (system call)
 fd = open("test.txt", O_RDONLY);
 if (fd == -1) {
 fprintf(stderr, "Error opening file: %s\n", strerror(errno));
 return 1;
 }

 // Read from file (system call)
 ssize_t bytes_read = read(fd, buffer, sizeof(buffer) - 1);
 if (bytes_read == -1) {
 perror("Read error");
 close(fd);
 return 1;
 }

 buffer[bytes_read] = '\0';
 printf("Read %zd bytes: %s\n", bytes_read, buffer);

 // Close file (system call)
 if (close(fd) == -1) {
 perror("Close error");
 return 1;
 }

 return 0;
}

#include <stdio.h>
#include <unistd.h>
#include <sys/types.h>
#include <wait.h>

int main() {
 pid_t pid;
 int status;

 printf("Parent: PID = %d\n", getpid());

 pid = fork();

 if (pid < 0) {
 perror("fork failed");
 return 1;
 }
 else if (pid == 0) {
 // Child process
 printf("Child: PID = %d, Parent PID = %d\n", getpid(), getppid());
 printf("Child: Executing new program...\n");

 // Normally would call exec() here
 return 42; // Child exit status
 }
 else {
 // Parent process
 printf("Parent: Created child with PID = %d\n", pid);

 // Wait for child to complete
 waitpid(pid, &status, 0);

 if (WIFEXITED(status)) {
 printf("Parent: Child exited with status %d\n", WEXITSTATUS(status));
 }
 }

 return 0;
}

#include <stdio.h>
#include <unistd.h>
#include <sys/types.h>
#include <string.h>
#include <wait.h>

int main() {
 int pipefd[2];
 pid_t pid;
 char parent_msg[] = "Hello from parent!";
 char child_buffer[100];

 // Create pipe before fork
 if (pipe(pipefd) == -1) {
 perror("pipe failed");
 return 1;
 }

 pid = fork();

 if (pid < 0) {
 perror("fork failed");
 return 1;
 }
 else if (pid == 0) {
 // Child process - read from pipe
 close(pipefd[1]); // Close write end

 ssize_t bytes_read = read(pipefd[0], child_buffer, sizeof(child_buffer));
 if (bytes_read > 0) {
 child_buffer[bytes_read] = '\0';
 printf("Child received: %s\n", child_buffer);
 }

 close(pipefd[0]);
 }
 else {
 // Parent process - write to pipe
 close(pipefd[0]); // Close read end

 printf("Parent sending: %s\n", parent_msg);
 write(pipefd[1], parent_msg, strlen(parent_msg));

 close(pipefd[1]); // Send EOF

 wait(NULL); // Wait for child
 }

 return 0;
}
